    at::Tensor result = at::empty({N, C_out, H_out, W_out}, options);

    at::Tensor bias_tensor = bias.has_value() ? *bias : at::Tensor();
    EXEC_NPU_CMD(aclnnConv2dDivideLeakyReluCustom, self, weight, bias_tensor, divisor, result);
